mapper.select:
SELECT ms.id, ms.standard_code AS standardCode, ms.part_code AS partCode, ms.part_name AS partName, ms.item_name AS itemName, ms.risk_factor AS riskFactor, ms.safety_measure AS safetyMeasure, ms.work_category AS workCategory, ms.work_content AS workContent, ms.acceptance_level AS acceptanceLevel, ms.maintenance_category AS maintenanceCategory, ms.profession, ms.cycle_value AS cycleValue, ms.cycle_unit AS cycleUnit, ms.last_completion_date AS lastCompletionDate, ms.next_schedule_date AS nextScheduleDate, ms.maintainer_id AS maintainerId, ms.maintainer_name AS maintainerName, ms.maintainer_username AS maintainerUsername, ms.maintenance_start_time AS maintenanceStartTime, ms.maintenance_end_time AS maintenanceEndTime, ms.created_at AS createdAt, ms.updated_at AS updatedAt FROM maintenance_standard ms
AND ms.maintainer_id = #{maintainerId}
AND ms.standard_code LIKE CONCAT('%', #{standardCode}, '%')
AND ms.part_code LIKE CONCAT('%', #{partCode}, '%')
AND ms.part_code IN
#{code}
AND ms.part_name LIKE CONCAT('%', #{partName}, '%')
AND ms.item_name LIKE CONCAT('%', #{itemName}, '%')
AND ms.profession = #{profession}
AND ms.maintenance_category = #{maintenanceCategory}
AND ms.maintenance_start_time >= #{maintenanceStartTime}
AND ms.maintenance_end_time <= #{maintenanceEndTime}
AND ms.work_category = #{workCategory}
AND ms.work_content LIKE CONCAT('%', #{workContent}, '%')
ORDER BY ms.id DESC

